let unitPrice = "{{unitPrice}}"
let shippingPrice = "{{shippingPrice}}"
let subtotal = "{{subtotalPrice}}";
let discount = "{{discount}}"
if (shippingPrice === "" || shippingPrice.includes("Free") || shippingPrice.includes("FREE")){
    shippingPrice = "0.00";
};
if (discount === ""){
    discount = "0.00";
};

let tax = "{{taxPrice}}";
if (tax === ""){
    tax = "0.00";
};
let total = "{{total}}";

unitPrice = Number(unitPrice.replace("{{Symbol}}","").replace(",","").trim());
shippingPrice = Number(shippingPrice.replace("{{Symbol}}","").replace(",","").trim());
discount = Number(discount.replace("{{Symbol}}","").replace(",","").trim());
subtotal = Number(subtotal.replace("{{Symbol}}","").replace(",","").trim());
tax = Number(tax.replace("{{Symbol}}","").replace(",","").trim());
total = Number(total.replace("{{Symbol}}","").replace(",","").trim());


let total2 = Number((subtotal-discount+tax+shippingPrice).toFixed(2));

return total === total2 && subtotal === unitPrice
